import React, { useState } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';

export default function ApplyPass() {
  const [rangeKm, setRangeKm] = useState('');
  const [documents, setDocuments] = useState({ collegeId: null, aadhar: null, feeReceipt: null });
  const [form, setForm] = useState({ from: '', to: '', passType: 'monthly' });
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const [loading, setLoading] = useState(false);
  const [step, setStep] = useState(1); // 1 = form, 2 = payment
  const navigate = useNavigate();

  const set = (k) => (e) => setForm({ ...form, [k]: e.target.value });

  const handleProceedToPayment = (e) => {
    e.preventDefault();
    setError('');
    // Validate range
    if (!rangeKm || isNaN(rangeKm)) {
      setError('Please enter a valid distance in km.');
      return;
    }
    if (Number(rangeKm) > 60) {
      setError('Range is exceeded. Maximum allowed is 60 km.');
      return;
    }
    // Validate documents
    if (!documents.collegeId || !documents.aadhar || !documents.feeReceipt) {
      setError('Please upload all three required documents.');
      return;
    }
    setStep(2);
  };

  const handlePaymentSubmit = async (e) => {
    e.preventDefault();
    setError(''); setSuccess(''); setLoading(true);
    try {
      const formData = new FormData();
      formData.append('from', form.from);
      formData.append('to', form.to);
      formData.append('passType', form.passType);
      formData.append('paymentStatus', 'completed');
      formData.append('rangeKm', rangeKm);
      // Append documents
      Object.entries(documents).forEach(([key, file]) => {
        if (file) formData.append(key, file);
      });
      await axios.post('/api/pass/apply', formData, { headers: { 'Content-Type': 'multipart/form-data' } });
      setSuccess('✅ Payment successful & Application submitted! Awaiting admin approval.');
      setTimeout(() => navigate('/my-passes'), 2500);
    } catch (err) {
      setError(err.response?.data?.message || 'Application failed');
    }
    setLoading(false);
  };

  return (
    <div className="center-card-layout">
      <div className="card-wrapper animate-fade-in" style={{ maxWidth: '520px' }}>
        <div className="glass-container">
          <h2 className="page-title" style={{ fontSize: '1.5rem', marginBottom: '24px' }}>
            {step === 1 ? '🎫 Apply for Bus Pass' : '💳 Complete Payment'}
          </h2>

          {error && <div className="alert alert-error">{error}</div>}
          {success && <div className="alert alert-success">{success}</div>}

          {step === 1 ? (
            <form onSubmit={handleProceedToPayment}>
              <div className="form-group">
                <label className="form-label">From (Boarding Point)</label>
                <input className="form-input" value={form.from} onChange={set('from')} required placeholder="e.g. Kuvempunagar" />
              </div>
              <div className="form-group">
                <label className="form-label">To (Destination)</label>
                <input className="form-input" value={form.to} onChange={set('to')} required placeholder="e.g. NIE College" />
              </div>
              <div className="form-group">
                <label className="form-label">Distance / Range (km)</label>
                <input className="form-input" type="number" value={rangeKm} onChange={e => setRangeKm(e.target.value)} required placeholder="e.g. 45" />
                <small style={{ color: 'var(--text-light)', fontSize: '12px' }}>Maximum allowed: 60 km</small>
              </div>
              <div className="form-group">
                <label className="form-label">Pass Type</label>
                <select className="form-select" value={form.passType} onChange={set('passType')}>
                  <option value="monthly">Monthly (₹500)</option>
                  <option value="quarterly">Quarterly (₹1400)</option>
                  <option value="yearly">Yearly (₹5000)</option>
                </select>
              </div>

              <hr style={{ border: 'none', borderTop: '1px solid rgba(255,255,255,0.1)', margin: '20px 0' }} />
              <h3 style={{ fontSize: '1rem', marginBottom: '16px', color: 'var(--text-color)' }}>📄 Required Documents</h3>

              <div className="form-group">
                <label className="form-label">College ID</label>
                <input type="file" className="form-input" accept="application/pdf,image/*" onChange={e => setDocuments({ ...documents, collegeId: e.target.files[0] })} required />
              </div>
              <div className="form-group">
                <label className="form-label">Aadhaar Card</label>
                <input type="file" className="form-input" accept="application/pdf,image/*" onChange={e => setDocuments({ ...documents, aadhar: e.target.files[0] })} required />
              </div>
              <div className="form-group">
                <label className="form-label">Fee Receipt</label>
                <input type="file" className="form-input" accept="application/pdf,image/*" onChange={e => setDocuments({ ...documents, feeReceipt: e.target.files[0] })} required />
              </div>

              <button className="btn btn-primary" style={{ marginTop: '12px' }}>Proceed to Payment ➔</button>
            </form>
          ) : (
            <form onSubmit={handlePaymentSubmit} className="animate-fade-in">
              <div className="form-group">
                <label className="form-label">Card Number (Mock)</label>
                <input className="form-input" required placeholder="4242 4242 4242 4242" defaultValue="4242 4242 4242 4242" />
              </div>
              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '16px' }}>
                <div className="form-group">
                  <label className="form-label">Expiry</label>
                  <input className="form-input" required placeholder="MM/YY" defaultValue="12/26" />
                </div>
                <div className="form-group">
                  <label className="form-label">CVV</label>
                  <input className="form-input" type="password" required placeholder="123" defaultValue="123" />
                </div>
              </div>
              <div style={{ display: 'flex', gap: '12px', marginTop: '10px' }}>
                <button type="button" className="btn btn-outline" onClick={() => setStep(1)} disabled={loading}>Back</button>
                <button className="btn btn-primary" type="submit" disabled={loading}>
                  {loading ? 'Processing...' : 'Pay Now'}
                </button>
              </div>
            </form>
          )}
        </div>
      </div>
    </div>
  );
}
